    public Dictionary<string, string> ParseConfigurationWithXmlReader(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        var xmlReaderSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Ignore,
            XmlResolver = null,
            MaxCharactersFromEntities = 1024,
            MaxCharactersInDocument = 10000000,
            IgnoreWhitespace = true,
            IgnoreComments = true
        };
        
        using (var reader = XmlReader.Create(xmlFilePath, xmlReaderSettings))
        {
            string currentPath = "";
            string currentKey = "";
            
            while (reader.Read())
            {
                switch (reader.NodeType)
                {
                    case XmlNodeType.Element:
                        currentKey = string.IsNullOrEmpty(currentPath) ? reader.Name : currentPath + "." + reader.Name;
                        
                        if (reader.HasAttributes)
                        {
                            while (reader.MoveToNextAttribute())
                            {
                                string attrKey = currentKey + "[@" + reader.Name + "]";
                                settings[attrKey] = reader.Value;
                            }
                            reader.MoveToElement();
                        }
                        
                        if (!reader.IsEmptyElement)
                        {
                            currentPath = currentKey;
                        }
                        break;
                        
                    case XmlNodeType.Text:
                        if (!string.IsNullOrWhiteSpace(reader.Value))
                        {
                            settings[currentPath] = reader.Value;
                        }
                        break;
                        
                    case XmlNodeType.EndElement:
                        int lastDotIndex = currentPath.LastIndexOf('.');
                        currentPath = lastDotIndex > 0 ? currentPath.Substring(0, lastDotIndex) : "";
                        break;
                }
            }
        }
        
        return settings;
    }
    
    private void ExtractSettings(XmlNode node, Dictionary<string, string> settings, string path)
    {
        if (node == null) return;
        
        string currentPath = string.IsNullOrEmpty(path) ? node.Name : path + "." + node.Name;
        
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string attrKey = currentPath + "[@" + attr.Name + "]";
                settings[attrKey] = attr.Value;
            }
        }
        
        if (node.HasChildNodes && node.ChildNodes.Count == 1 && node.FirstChild.NodeType == XmlNodeType.Text)
        {
            settings[currentPath] = node.FirstChild.Value;
        }
        else if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    ExtractSettings(child, settings, currentPath);
                }
            }
        }
    }
